## 2. reducers（conversation.ts `reducers: {}` 内，建议放在 `setGoal` 之后 line 442 附近）

> 全部用 ID 生成助手：复用文件内已有约定。conversation.ts 没现成 `genId`，工具 handler 侧 dispatch 时传入 id（见数据流），或在 reducer 内用 `crypto.randomUUID?.() ?? fallback`。**建议：id 由调用方（工具 handler）生成并放进 payload**，reducer 只消费——与 addMessage 等现有 reducer 让调用方带 id 的风格一致，避免 reducer 内产生副作用 id。

### 2.1 beginTaskBoundary

```ts
// ★ 开新任务边界：前一个 active 自动收为 done（endedAt 回填）。新边界初始 history 含一条初始项。
beginTaskBoundary(state, action: PayloadAction<{
  id: string; headline: string; summary?: string; anchorMessageId?: string; startRound?: number; at?: number;
}>) {
  const now = action.payload.at ?? Date.now();
  if (!state.taskBoundaries) state.taskBoundaries = [];
  // 收口上一个 active（隐式收口，规范 §10.2「begin 下一个隐式收口」）
  for (const b of state.taskBoundaries) {
    if (b.status === 'active') { b.status = 'done'; b.endedAt = now; }
  }
  const headline = action.payload.headline;
  const summary = action.payload.summary ?? '';
  state.taskBoundaries.push({
    id: action.payload.id,
    headline, summary,
    status: 'active',
    startedAt: now,
    anchorMessageId: action.payload.anchorMessageId,
    startRound: action.payload.startRound,
    steps: [],
    history: [{ headline, summary, timestamp: now }],  // 初始项即第一条变迁
  });
  // 同步顶部镜像
  state.taskHeadline = { headline, summary, updatedAt: now };
},
```

### 2.2 setTaskHeadline（★ 变更即 push history）

```ts
// ★ 设/更新顶部大标题 + 概述。每次变更：① 刷 taskHeadline 镜像 ② 给当前 active boundary.history push 一条。
//   规范要求「每个内部小标题都自动强制更新」——AI 每推进一个子标题调一次本 reducer。
setTaskHeadline(state, action: PayloadAction<{ headline: string; summary?: string; at?: number }>) {
  const now = action.payload.at ?? Date.now();
  const headline = action.payload.headline;
  const summary = action.payload.summary ?? state.taskHeadline?.summary ?? '';
  state.taskHeadline = { headline, summary, updatedAt: now };
  // 把变更也记进当前 active boundary 的 history + 同步其 headline/summary 字段
  const active = state.taskBoundaries?.find(b => b.status === 'active');
  if (active) {
    active.headline = headline;
    active.summary = summary;
    active.history.push({ headline, summary, timestamp: now });  // ★ 时间线增长点
  }
},
```

> 边界：无 active boundary 时（AI 还没 begin 就先 set headline），只刷镜像、不 push（history 无处可挂）。这是合理降级——顶部条仍显示，开 boundary 后再记。

### 2.3 appendTaskStep

```ts
// ★ 给当前 active 边界追加一条进度 step。无 active 则 no-op（AI 该先 begin）。
appendTaskStep(state, action: PayloadAction<{ id: string; text: string; toolCallIds?: string[]; at?: number }>) {
  const active = state.taskBoundaries?.find(b => b.status === 'active');
  if (!active) return;
  active.steps.push({
    id: action.payload.id,
    text: action.payload.text,
    timestamp: action.payload.at ?? Date.now(),
    toolCallIds: action.payload.toolCallIds,
  });
},
```

### 2.4 endTaskBoundary（显式收口，规范用户拍板用显式收口）

```ts
// ★ 显式收口当前 active 边界（status='done'）。传 id 收指定边界；不传收当前 active。
//   aborted=true 时收为 'aborted'（红）。规范用户拍板：收口由 AI 显式调结束工具，不自动推断。
endTaskBoundary(state, action: PayloadAction<{ id?: string; aborted?: boolean; at?: number } | undefined>) {
  const p = action.payload ?? {};
  const now = p.at ?? Date.now();
  const target = p.id
    ? state.taskBoundaries?.find(b => b.id === p.id)
    : state.taskBoundaries?.find(b => b.status === 'active');
  if (!target) return;
  target.status = p.aborted ? 'aborted' : 'done';
  target.endedAt = now;
},
```

