### 1.8 ★ 历史变迁浮层组件 `TaskBoundaryHistoryPopover`（同文件内定义；仿 ContextMenu.tsx 第 20-75 行 createPortal + mousedown 点外关闭 + 视口边界夹取）
```tsx
function TaskBoundaryHistoryPopover({ entries, position, onClose }:
  { entries: TaskBoundaryHistoryEntry[]; position:{x:number;y:number}; onClose:()=>void }) {
  const ref = useRef<HTMLDivElement>(null);
  // 点外关闭（照搬 ContextMenu handleClickOutside + useEffect addEventListener('mousedown')）
  useEffect(() => {
    const h = (e: MouseEvent) => { if (ref.current && !ref.current.contains(e.target as Node)) onClose(); };
    document.addEventListener('mousedown', h);
    // 额外：Esc 关闭
    const k = (e: KeyboardEvent) => { if (e.key === 'Escape') onClose(); };
    document.addEventListener('keydown', k);
    return () => { document.removeEventListener('mousedown', h); document.removeEventListener('keydown', k); };
  }, [onClose]);
  // 视口夹取（仿 ContextMenu 第 34-36 行，浮层宽 320，估高按条数，最大高度由 CSS max-height + overflow 兜底）
  const adjustedX = Math.min(position.x, window.innerWidth - 340);
  const adjustedY = Math.min(position.y, window.innerHeight - 360);
  // 时间线：最新在上（倒序渲染），每条 = headline + summary + 相对时间
  const ordered = [...entries].reverse();
  return createPortal(
    <div ref={ref} className="tb-history-popover glass-panel"
         style={{ position:'fixed', left:adjustedX, top:adjustedY, zIndex:9999 }}>
      <div className="tb-history-head">
        <History size={13}/><span>标题 / 概述变更历史</span>
        <button className="tb-history-close" onClick={onClose}><X size={13}/></button>
      </div>
      {ordered.length === 0 ? (
        <div className="tb-history-empty">暂无变更记录</div>
      ) : (
        <ol className="tb-history-timeline">
          {ordered.map((h, i) => (
            <li className={`tb-history-item${i===0 ? ' current' : ''}`} key={h.timestamp + '-' + i}>
              <span className="tb-history-node" />
              <div className="tb-history-body">
                <div className="tb-history-line-top">
                  <strong className="tb-history-headline">{h.headline}</strong>
                  <span className="tb-history-time">{relTime(h.timestamp)}</span>
                  {i===0 && <span className="tb-history-badge">当前</span>}
                </div>
                <div className="tb-history-summary">{h.summary}</div>
              </div>
            </li>
          ))}
        </ol>
      )}
    </div>,
    document.body,
  );
}
```

### 1.9 工具函数（组件文件内私有）
- `formatDuration(startedAt, endedAt, now)`：照搬 WorkflowCard.formatDuration 逻辑（<1s/Ns/Nm Ns）。
- `fileName(path)`：`path.split(/[\\/]/).pop() || path`（与 MessageBubble 同）。
- `relTime(ts)`：相对时间「刚刚 / N秒前 / N分钟前 / N小时前 / 否则 toLocaleTimeString」。⚠️ 坑：规范 §问题1 时间戳已统一为秒还是毫秒要核对——history.timestamp 与 step.timestamp 必须同单位。若数据层写入用 `Date.now()`（ms），relTime 按 ms 算；本层 relTime 内部先判断 `ts < 1e12 ? ts*1000 : ts` 兜底归一到 ms 再算，避免单位漂移导致显示「55年前」。

